    private int outputOptions(SDBQuery q, String startsWith, int domainId, int titleDomain, Writer writer, Set<Integer> options, int exactMatchNodeId, NUIFilterSet filterSet, APIQuery aq, int limit) throws IOException {
        SDBNode node;
        int count = 0;

        while ((node = q.next()) != null) {
            String option = node.getValue();
            int matchLoc = option.toUpperCase().indexOf(startsWith.toUpperCase());
            if (count >= limit) break;//[BugId:09658]

            //do check to see if really match criteria, don't waste MAXCOUNT if not totally match criteria
            if (matchLoc >= 0 && //really matches
                    (matchLoc == 0 || option.charAt(matchLoc - 1) == ' ' || //starts with it, or a new word starts with it
                            Encoder.ifChinese(option.charAt(matchLoc - 1)) || Encoder.ifChinese(option.charAt(matchLoc))) //space or chinese character okay
                    ) {

                SDBNode rootNode = null;
                //check dynamic filters
                //This check is too slow so it's removed
                //https://www.ragic.com/tickets/ragic/1#!/1/75241
                //https://www.ragic.com/sims/task/detail.jsp?a=teamragic&id=14323
                if (aq != null && filterSet != null && !filterSet.getFilters().isEmpty() && titleDomain != 0) {
                    rootNode = q.dipNode(domainId);
                    if (rootNode == null) continue;
                    APIEntry e = aq.getAPIEntry(rootNode.getId());
                    //System.out.println(e.getJSON().toString());
                    if (e != null && !e.checkFilterSet(filterSet, aq.getUser(), aq.getBundle())) {
                        continue;
                    }
                }

                if (titleDomain == 0) {
                    if (exactMatchNodeId==node.getId()){//exact match found, let caller know by including exact match in the options set, but no duplicated output
                        options.add(node.getId());
                        continue;
                    }
                    else if (options != null && options.contains(node.getId())) continue;
                    writer.write(node.getId() + "|" + node.getValue() + "\n");
                    options.add(node.getId());
                    count++;
                } else {
                    if (rootNode == null) rootNode = q.dipNode(domainId);
                    if (rootNode != null) {
                        if (exactMatchNodeId==node.getId()){//exact match found, let caller know by including exact match in the options set, but no duplicated output
                            options.add(node.getId());
                            continue;
                        }
                        if (options != null && options.contains(rootNode.getId())) continue;
                        writer.write(rootNode.getId() + "|" + node.getValue() + "\n");
                        options.add(rootNode.getId());
                        count++;
                    }
                }
            }
        }
        return count;
    }

